//! # Pneuma Voice Codecs — Rust Implementation
//!
//! Port of `open-source/bitwise/src/{phoneme-codec,prosody-codec,residual-codec}.ts`.
//! Implements byte-level Huffman coding with domain-specific priors for
//! efficient transport of voice-as-metadata.

// ─────────────────────────────────────────────────────────────────────────────
// Huffman Core
// ─────────────────────────────────────────────────────────────────────────────

pub struct Histogram {
    pub counts: [u32; 256],
}

#[derive(Clone)]
pub enum PriorNode {
    Leaf {
        symbol: u8,
    },
    Branch {
        left: Box<PriorNode>,
        right: Box<PriorNode>,
    },
}

pub struct CompiledPrior {
    pub codes: [Option<Vec<u8>>; 256],
    pub root: PriorNode,
}

impl CompiledPrior {
    pub fn compile(h: Histogram) -> Self {
        #[derive(Clone)]
        struct Node {
            weight: u32,
            tree: ArcTree,
        }

        #[derive(Clone)]
        enum ArcTree {
            Leaf(u8),
            Branch(Box<ArcTree>, Box<ArcTree>),
        }

        let mut nodes: Vec<Node> = Vec::new();
        for s in 0..256 {
            let w = h.counts[s];
            if w > 0 {
                nodes.push(Node {
                    weight: w,
                    tree: ArcTree::Leaf(s as u8),
                });
            }
        }

        if nodes.is_empty() {
            panic!("Histogram has no positive-count symbols");
        }

        // Degenerate single-symbol case
        if nodes.len() == 1 {
            let symbol = match nodes[0].tree {
                ArcTree::Leaf(s) => s,
                _ => unreachable!(),
            };
            let leaf = Box::new(PriorNode::Leaf { symbol });
            return CompiledPrior {
                codes: {
                    let mut c = [const { None }; 256];
                    c[symbol as usize] = Some(vec![0]);
                    c
                },
                root: PriorNode::Branch {
                    left: leaf.clone(),
                    right: leaf,
                },
            };
        }

        nodes.sort_by(|a, b| a.weight.cmp(&b.weight));

        while nodes.len() > 1 {
            let left = nodes.remove(0);
            let right = nodes.remove(0);
            let combined = Node {
                weight: left.weight + right.weight,
                tree: ArcTree::Branch(Box::new(left.tree), Box::new(right.tree)),
            };

            let mut i = 0;
            while i < nodes.len() && nodes[i].weight <= combined.weight {
                i += 1;
            }
            nodes.insert(i, combined);
        }

        let root_arc = nodes.remove(0).tree;

        fn convert(arc: ArcTree) -> Box<PriorNode> {
            match arc {
                ArcTree::Leaf(s) => Box::new(PriorNode::Leaf { symbol: s }),
                ArcTree::Branch(l, r) => Box::new(PriorNode::Branch {
                    left: convert(*l),
                    right: convert(*r),
                }),
            }
        }

        let root = convert(root_arc);
        let mut codes: [Option<Vec<u8>>; 256] = [const { None }; 256];

        fn walk(node: &PriorNode, prefix: &mut Vec<u8>, codes: &mut [Option<Vec<u8>>; 256]) {
            match node {
                PriorNode::Leaf { symbol } => {
                    codes[*symbol as usize] = Some(prefix.clone());
                }
                PriorNode::Branch { left, right } => {
                    prefix.push(0);
                    walk(left, prefix, codes);
                    prefix.pop();
                    prefix.push(1);
                    walk(right, prefix, codes);
                    prefix.pop();
                }
            }
        }

        walk(&root, &mut Vec::new(), &mut codes);
        CompiledPrior { codes, root: *root }
    }
}

pub struct EncodedBitstream {
    pub bytes: Vec<u8>,
    pub bit_length: usize,
}

pub fn encode_huffman(prior: &CompiledPrior, input: &[u8]) -> EncodedBitstream {
    let mut out = Vec::new();
    let mut bit_pos = 0;
    let mut current_byte = 0u8;

    for &symbol in input {
        let code = prior.codes[symbol as usize]
            .as_ref()
            .expect("Symbol not in prior");
        for &bit in code {
            if bit == 1 {
                current_byte |= 1 << (7 - (bit_pos % 8));
            }
            bit_pos += 1;
            if bit_pos % 8 == 0 {
                out.push(current_byte);
                current_byte = 0;
            }
        }
    }

    if bit_pos % 8 != 0 {
        out.push(current_byte);
    }

    EncodedBitstream {
        bytes: out,
        bit_length: bit_pos,
    }
}

pub fn decode_huffman(
    prior: &CompiledPrior,
    stream: &EncodedBitstream,
    expected_len: usize,
) -> Vec<u8> {
    let mut out = Vec::with_capacity(expected_len);
    let mut node = &prior.root;

    for bit_pos in 0..stream.bit_length {
        let byte_idx = bit_pos / 8;
        let bit_idx = 7 - (bit_pos % 8);
        let bit = (stream.bytes[byte_idx] >> bit_idx) & 1;

        node = match node {
            PriorNode::Leaf { .. } => unreachable!("Hit leaf mid-bitstream"),
            PriorNode::Branch { left, right } => {
                if bit == 0 {
                    left
                } else {
                    right
                }
            }
        };

        if let PriorNode::Leaf { symbol } = node {
            out.push(*symbol);
            node = &prior.root;
        }
    }

    if out.len() != expected_len {
        panic!(
            "Huffman decode produced {} bytes, expected {}",
            out.len(),
            expected_len
        );
    }
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// Priors
// ─────────────────────────────────────────────────────────────────────────────

pub fn phoneme_histogram() -> Histogram {
    let mut counts = [1u32; 256];
    let emphasis = vec![
        (1, 1000),
        (3, 224),
        (4, 253),
        (5, 237),
        (9, 329),
        (12, 297),
        (30, 333),
        (34, 409),
        (36, 362),
    ];
    for (k, v) in emphasis {
        counts[k as usize] = v;
    }
    Histogram { counts }
}

pub fn prosody_histogram() -> Histogram {
    let mut counts = [1u32; 256];
    let emphasis = vec![
        (0x00, 1500),
        (0x01, 600),
        (0x10, 600),
        (0xff, 600),
        (0x0f, 500),
        (0xf0, 500),
        (0x11, 400),
    ];
    for (k, v) in emphasis {
        counts[k as usize] = v;
    }
    Histogram { counts }
}

pub fn voice_residual_histogram() -> Histogram {
    let mut counts = [10u32; 256];
    let emphasis = vec![
        (0x00, 4000),
        (0xff, 4000),
        (0x01, 600),
        (0xfe, 600),
        (0x02, 250),
        (0xfd, 250),
    ];
    for (k, v) in emphasis {
        counts[k as usize] = v;
    }
    Histogram { counts }
}

// ─────────────────────────────────────────────────────────────────────────────
// Phoneme Codec
// ─────────────────────────────────────────────────────────────────────────────

pub const PHONEME_TAG: u8 = 0x04;

pub fn encode_phonemes(ids: &[u8]) -> Vec<u8> {
    if ids.is_empty() {
        return vec![PHONEME_TAG, 0, 0, 0, 0, 0, 0, 0, 0];
    }

    use flate2::write::GzEncoder;
    use flate2::Compression;
    use std::io::Write;

    let mut encoder = GzEncoder::new(Vec::new(), Compression::default());
    encoder.write_all(ids).unwrap();
    let compressed = encoder.finish().unwrap();

    let mut out = Vec::with_capacity(9 + compressed.len());
    out.push(PHONEME_TAG);
    out.extend_from_slice(&(ids.len() as u32).to_be_bytes());
    out.extend_from_slice(&(compressed.len() as u32).to_be_bytes());
    out.extend_from_slice(&compressed);
    out
}

pub fn decode_phonemes(packet: &[u8]) -> Vec<u8> {
    if packet[0] != PHONEME_TAG {
        panic!("Wrong tag");
    }
    let count = u32::from_be_bytes(packet[1..5].try_into().unwrap()) as usize;
    let comp_len = u32::from_be_bytes(packet[5..9].try_into().unwrap()) as usize;

    if count == 0 {
        return vec![];
    }

    use flate2::read::GzDecoder;
    use std::io::Read;

    let mut decoder = GzDecoder::new(&packet[9..9 + comp_len]);
    let mut out = Vec::with_capacity(count);
    decoder.read_to_end(&mut out).unwrap();
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// Prosody Codec
// ─────────────────────────────────────────────────────────────────────────────

pub const PROSODY_TAG: u8 = 0x05;
const RESET_ESCAPE: u8 = 0x80;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct ProsodyFrame {
    pub f0_bin: u8,
    pub energy_bin: u8,
}

pub fn encode_prosody(frames: &[ProsodyFrame]) -> Vec<u8> {
    if frames.is_empty() {
        return vec![PROSODY_TAG, 0, 0, 0, 0, 0, 0, 0, 0];
    }

    let mut bytes = Vec::new();
    let mut prev: Option<ProsodyFrame> = None;

    for &f in frames {
        if let Some(p) = prev {
            let f0_delta = (f.f0_bin as i32 - p.f0_bin as i32) as i8;
            let ene_delta = (f.energy_bin as i32 - p.energy_bin as i32) as i8;

            if (-7..=7).contains(&f0_delta) && (-7..=7).contains(&ene_delta) {
                let f4 = (f0_delta as u8) & 0x0f;
                let e4 = (ene_delta as u8) & 0x0f;
                bytes.push((f4 << 4) | e4);
            } else {
                bytes.push(RESET_ESCAPE);
                bytes.push(f.f0_bin);
                bytes.push(f.energy_bin);
            }
        } else {
            bytes.push(RESET_ESCAPE);
            bytes.push(f.f0_bin);
            bytes.push(f.energy_bin);
        }
        prev = Some(f);
    }

    let prior = CompiledPrior::compile(prosody_histogram());
    let bitstream = encode_huffman(&prior, &bytes);

    let mut out = Vec::with_capacity(9 + bitstream.bytes.len());
    out.push(PROSODY_TAG);
    out.extend_from_slice(&(frames.len() as u16).to_be_bytes());
    out.extend_from_slice(&(bytes.len() as u32).to_be_bytes()[1..4]); // u24
    out.extend_from_slice(&(bitstream.bit_length as u32).to_be_bytes()[1..4]); // u24
    out.extend_from_slice(&bitstream.bytes);
    out
}

pub fn decode_prosody(packet: &[u8]) -> Vec<ProsodyFrame> {
    if packet[0] != PROSODY_TAG {
        panic!("Wrong tag");
    }
    let frame_count = u16::from_be_bytes(packet[1..3].try_into().unwrap()) as usize;

    let mut u24_bytes = [0u8; 4];
    u24_bytes[1..4].copy_from_slice(&packet[3..6]);
    let inner_byte_count = u32::from_be_bytes(u24_bytes) as usize;

    u24_bytes[1..4].copy_from_slice(&packet[6..9]);
    let bit_length = u32::from_be_bytes(u24_bytes) as usize;

    if frame_count == 0 {
        return vec![];
    }

    let prior = CompiledPrior::compile(prosody_histogram());
    let stream = EncodedBitstream {
        bytes: packet[9..].to_vec(),
        bit_length,
    };
    let decoded_bytes = decode_huffman(&prior, &stream, inner_byte_count);

    let mut out = Vec::with_capacity(frame_count);
    let mut prev: Option<ProsodyFrame> = None;
    let mut i = 0;
    while i < decoded_bytes.len() && out.len() < frame_count {
        let b = decoded_bytes[i];
        if b == RESET_ESCAPE {
            let f0_bin = decoded_bytes[i + 1];
            let energy_bin = decoded_bytes[i + 2];
            let frame = ProsodyFrame { f0_bin, energy_bin };
            out.push(frame);
            prev = Some(frame);
            i += 3;
        } else {
            let p = prev.expect("First frame must be reset");
            let f4 = (b >> 4) & 0x0f;
            let e4 = b & 0x0f;
            let f0_delta = if f4 >= 8 { f4 as i32 - 16 } else { f4 as i32 };
            let ene_delta = if e4 >= 8 { e4 as i32 - 16 } else { e4 as i32 };
            let frame = ProsodyFrame {
                f0_bin: (p.f0_bin as i32 + f0_delta) as u8,
                energy_bin: (p.energy_bin as i32 + ene_delta) as u8,
            };
            out.push(frame);
            prev = Some(frame);
            i += 1;
        }
    }
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// Residual Codec
// ─────────────────────────────────────────────────────────────────────────────

pub const RESIDUAL_TAG: u8 = 0x06;

pub fn encode_residual(samples: &[i16]) -> Vec<u8> {
    if samples.is_empty() {
        return vec![RESIDUAL_TAG, 0, 0, 0, 0, 0, 0, 0, 0];
    }

    let mut inner_bytes = Vec::with_capacity(samples.len() * 2);
    for &s in samples {
        inner_bytes.extend_from_slice(&s.to_le_bytes());
    }

    let prior = CompiledPrior::compile(voice_residual_histogram());
    let bitstream = encode_huffman(&prior, &inner_bytes);

    let mut out = Vec::with_capacity(9 + bitstream.bytes.len());
    out.push(RESIDUAL_TAG);
    out.extend_from_slice(&(samples.len() as u32).to_be_bytes());
    out.extend_from_slice(&(bitstream.bit_length as u32).to_be_bytes());
    out.extend_from_slice(&bitstream.bytes);
    out
}

pub fn decode_residual(packet: &[u8]) -> Vec<i16> {
    if packet[0] != RESIDUAL_TAG {
        panic!("Wrong tag");
    }
    let sample_count = u32::from_be_bytes(packet[1..5].try_into().unwrap()) as usize;
    let bit_length = u32::from_be_bytes(packet[5..9].try_into().unwrap()) as usize;

    if sample_count == 0 {
        return vec![];
    }

    let prior = CompiledPrior::compile(voice_residual_histogram());
    let stream = EncodedBitstream {
        bytes: packet[9..].to_vec(),
        bit_length,
    };
    let decoded = decode_huffman(&prior, &stream, sample_count * 2);

    let mut out = Vec::with_capacity(sample_count);
    for i in 0..sample_count {
        let lo = decoded[i * 2];
        let hi = decoded[i * 2 + 1];
        out.push(i16::from_le_bytes([lo, hi]));
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_huffman_roundtrip() {
        let h = phoneme_histogram();
        let prior = CompiledPrior::compile(h);
        let input = vec![1, 30, 34, 1, 36, 1];
        let encoded = encode_huffman(&prior, &input);
        let decoded = decode_huffman(&prior, &encoded, input.len());
        assert_eq!(input, decoded);
    }

    #[test]
    fn test_phoneme_codec() {
        let input = vec![1, 3, 4, 5, 9, 12, 30, 34, 36];
        let packet = encode_phonemes(&input);
        let decoded = decode_phonemes(&packet);
        assert_eq!(input, decoded);
    }

    #[test]
    fn test_prosody_codec() {
        let input = vec![
            ProsodyFrame {
                f0_bin: 10,
                energy_bin: 20,
            },
            ProsodyFrame {
                f0_bin: 11,
                energy_bin: 21,
            },
            ProsodyFrame {
                f0_bin: 10,
                energy_bin: 20,
            },
        ];
        let packet = encode_prosody(&input);
        let decoded = decode_prosody(&packet);
        assert_eq!(input, decoded);
    }

    #[test]
    fn test_residual_codec() {
        let input = vec![0i16, 1, -1, 100, -100, 5000, -5000];
        let packet = encode_residual(&input);
        let decoded = decode_residual(&packet);
        assert_eq!(input, decoded);
    }
}
